import{_ as o,o as c,c as t,ag as d}from"./chunks/framework.NsnsQ6zO.js";const m=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),l={name:"changelog.md"};function i(a,e,r,n,s,u){return c(),t("div",null,[...e[0]||(e[0]=[d('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to AgentVM will be documented in this file.</p><p>The format is based on <a href="https://keepachangelog.com/en/1.1.0/" target="_blank" rel="noreferrer">Keep a Changelog</a>, and this project adheres to <a href="https://semver.org/spec/v2.0.0.html" target="_blank" rel="noreferrer">Semantic Versioning</a>.</p><h2 id="unreleased" tabindex="-1"><a href="https://github.com/llmhut/agentvm/compare/v0.3.0...HEAD" target="_blank" rel="noreferrer">Unreleased</a> <a class="header-anchor" href="#unreleased" aria-label="Permalink to &quot;[Unreleased]&quot;">​</a></h2><p>Nothing yet — v0.3.0 is the current release.</p><hr><h2 id="_0-3-0-—-2026-05-05" tabindex="-1"><a href="https://github.com/llmhut/agentvm/compare/v0.2.3...v0.3.0" target="_blank" rel="noreferrer">0.3.0</a> — 2026-05-05 <a class="header-anchor" href="#_0-3-0-—-2026-05-05" aria-label="Permalink to &quot;[0.3.0] — 2026-05-05&quot;">​</a></h2><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Framework Adapters</strong> (<code>src/adapters/</code>) <ul><li><strong>LangChain.js adapter</strong> (<code>adapters/langchain.ts</code>) <ul><li><code>toolToLangChain(tool)</code> — convert a single AgentVM tool to LangChain <code>DynamicStructuredTool</code> shape</li><li><code>toLangChainTools(kernel, filter?)</code> — convert all (or filtered) tools at once</li><li><code>toLangChainMemory(kernel, namespace, options?)</code> — use AgentVM memory as LangChain <code>BaseMemory</code><ul><li>Supports <code>memoryKey</code>, <code>maxEntries</code>, <code>returnFormat</code> (&#39;string&#39; | &#39;array&#39;)</li><li><code>loadMemoryVariables()</code>, <code>saveContext()</code>, <code>clear()</code> interface</li></ul></li></ul></li><li><strong>Vercel AI SDK adapter</strong> (<code>adapters/vercel-ai.ts</code>) <ul><li><code>toolToAISDK(tool)</code> — convert a single tool to AI SDK <code>tool()</code> format</li><li><code>toAISDKTools(kernel, filter?)</code> — returns <code>Record&lt;string, tool&gt;</code> for <code>generateText({ tools })</code></li><li><code>createUsageTracker(kernel, namespace)</code> — record AI SDK token usage into AgentVM memory</li></ul></li><li><strong>Generic adapter</strong> (<code>adapters/generic.ts</code>) <ul><li><code>toOpenAITools(kernel)</code> — OpenAI function-calling format (works with LiteLLM, Ollama, etc.)</li><li><code>toAnthropicTools(kernel)</code> — Anthropic tool format (<code>name</code>, <code>description</code>, <code>input_schema</code>)</li><li><code>createToolExecutor(kernel)</code> — generic <code>(toolName, args) =&gt; result</code> for any model response</li><li><code>serveMCP(kernel)</code> — expose AgentVM tools as an MCP server over stdio (for Claude Desktop, Cursor, etc.)</li><li><code>describeTools(kernel)</code> — human-readable tool summary for debugging</li></ul></li><li>All adapters are zero-dependency — they produce plain objects matching each framework&#39;s interface</li><li>34 adapter tests covering all conversion formats and integration with built-in tools</li></ul></li><li><strong>Pluggable Memory Backends</strong><ul><li><code>MemoryBackend</code> interface — 8-method contract (<code>get</code>, <code>set</code>, <code>delete</code>, <code>list</code>, <code>clear</code>, <code>deleteNamespace</code>, <code>stats</code>, <code>close</code>)</li><li><code>InMemoryBackend</code> — refactored default backend, fully backward compatible</li><li><code>SqliteBackend</code> — file-based persistence using sql.js (pure WASM, no native bindings) <ul><li><code>SqliteBackend.create(&#39;./data.db&#39;)</code> — async factory, loads existing DB or creates new</li><li>Auto-flush dirty writes to disk every 5 seconds</li><li><code>flush()</code> for manual persistence, <code>close()</code> for graceful shutdown</li></ul></li><li><code>MemoryBus</code> now accepts any <code>MemoryBackend</code> via constructor</li><li><code>MemoryBus.statsAsync()</code> — full async stats from the backend</li><li><code>MemoryBus.close()</code> — flush and release backend resources</li></ul></li><li><strong>Agent Contract Enforcement</strong><ul><li><code>validateSchema()</code> — recursive schema validator for <code>string</code>, <code>number</code>, <code>boolean</code>, <code>object</code>, <code>array</code> with nested <code>properties</code>, <code>required</code>, and <code>items</code></li><li><code>validateInput()</code> / <code>validateOutput()</code> — called automatically in <code>Kernel.execute()</code> when agent has a <code>contract</code></li><li><code>ContractValidationError</code> — thrown with agent name, phase (<code>input</code>/<code>output</code>), and violation details</li><li>SLA enforcement — <code>Kernel.execute()</code> emits <code>contract:sla:latency</code> event when execution exceeds <code>contract.maxLatency</code></li></ul></li><li><strong>YAML Config System</strong><ul><li><code>loadConfig(&#39;agentvm.yml&#39;)</code> — parse, validate, and return typed <code>AgentVMConfig</code></li><li>Built-in YAML parser (zero dependencies) — handles nested objects, arrays (block + flow), scalars, comments</li><li><code>validateConfig()</code> — checks types, required fields, valid enums; returns array of error messages</li><li><code>ConfigValidationError</code> with all violations listed</li><li>Environment variable overrides via <code>env:</code> section in YAML</li></ul></li><li><strong>Checkpointing</strong><ul><li><code>checkpoint(kernel, processId, path)</code> — serialize process metadata + full memory snapshot to JSON</li><li><code>restore(kernel, path)</code> — spawn a new process and restore all memory from checkpoint file</li><li><code>readCheckpoint(path)</code> — inspect checkpoint data without restoring</li></ul></li><li><strong>Resource Tracking &amp; Kernel Stats</strong><ul><li><code>ExecutionResult.tokensUsed</code> — automatically populated from <code>__llm_usage</code> in process memory</li><li><code>Kernel.stats()</code> — aggregate stats: agents, processes by state, memory backend info, tools, channels, total tokens</li></ul></li><li><code>ProcessOptions.tokenBudget</code> — type added for per-process token limits</li><li><code>KernelConfig.memoryBackend</code> — pass a <code>MemoryBackend</code> instance to the kernel constructor</li><li>New type exports: <code>MemoryBackend</code>, <code>MemoryBackendStats</code>, <code>AgentVMConfig</code>, <code>CheckpointData</code>, <code>KernelStats</code></li><li>114 new unit tests (333 total across 9 test files)</li></ul><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><code>MemoryBus</code> — rewritten to use <code>MemoryBackend</code> interface internally (backward compatible API)</li><li><code>Kernel</code> constructor — accepts <code>memoryBackend</code> in config, passes it to <code>MemoryBus</code></li><li><code>Kernel.execute()</code> — now validates input/output contracts, tracks resource usage, checks SLA latency</li><li><code>src/index.ts</code> — exports config, checkpoint, and all new backend modules</li></ul><h3 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h3><ul><li>Added <code>sql.js</code> (pure WASM SQLite) as optional dependency for <code>SqliteBackend</code></li></ul><hr><h2 id="_0-2-2-—-2026-04-11" tabindex="-1"><a href="https://github.com/llmhut/agentvm/compare/v0.2.1...v0.2.2" target="_blank" rel="noreferrer">0.2.2</a> — 2026-04-11 <a class="header-anchor" href="#_0-2-2-—-2026-04-11" aria-label="Permalink to &quot;[0.2.2] — 2026-04-11&quot;">​</a></h2><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><code>MCPClient</code> — connect to MCP servers over stdio or SSE transport, auto-discover and register tools <ul><li>Full JSON-RPC 2.0 message passing with timeout handling</li><li>Tool auto-registration: discovered tools appear in the <code>ToolRouter</code> as <code>mcp:&lt;server&gt;:&lt;tool&gt;</code></li><li>Resource discovery via <code>resources/list</code></li><li><code>connect()</code>, <code>disconnect()</code>, <code>disconnectAll()</code>, <code>callTool()</code>, <code>readResource()</code> API</li></ul></li><li><code>createLLMAgent()</code> factory — create AI agents backed by Anthropic or OpenAI models <ul><li>Full agentic tool-use loop (up to <code>maxTurns</code>, default 10)</li><li>Conversation history persisted in process memory across executions</li><li>Token usage tracking in <code>__llm_usage</code> memory key</li><li><code>onBeforeCall</code>, <code>onAfterCall</code>, <code>onToolCall</code> hooks</li><li>Both Anthropic (<code>claude-*</code>) and OpenAI (<code>gpt-*</code>) provider support</li></ul></li><li><code>createPipeline()</code> — chain agents sequentially; each agent&#39;s output feeds the next</li><li>Built-in tools (<code>src/builtins/tools.ts</code>) — practical tools ready to register: <ul><li><code>http_fetch</code> — HTTP GET/POST/etc with headers, body, timeout (60 req/min)</li><li><code>json_fetch</code> — fetch + auto-parse JSON response</li><li><code>shell_exec</code> — run shell commands, returns <code>{ stdout, stderr, exitCode }</code></li><li><code>file_read</code> — read files with size limit guard</li><li><code>file_write</code> — write/append files, creates parent directories</li><li><code>wait</code> — sleep for N milliseconds (capped at 60s, respects AbortSignal)</li><li><code>registerBuiltins(kernel)</code> convenience function</li></ul></li><li>Kernel injects <code>__tool_schemas</code> into process memory at spawn time so LLM agents can discover tool definitions</li><li>New example projects: <code>llm-pipeline.ts</code> (researcher → writer → editor chain), <code>mcp-agent.ts</code> (filesystem MCP server integration), <code>llm-research-agent.ts</code></li><li>MCP types exported: <code>MCPServerConfig</code>, <code>MCPTool</code>, <code>MCPResource</code></li><li>LLM types exported: <code>LLMAgentConfig</code>, <code>LLMMessage</code>, <code>LLMResponse</code></li><li>Unit tests for LLM agent (<code>tests/unit/llm.test.ts</code>) and MCP client (<code>tests/unit/mcp.test.ts</code>, <code>tests/unit/mcp-stdio.test.ts</code>)</li><li>Fake MCP server fixture for integration testing (<code>tests/fixtures/fake-mcp-server.mjs</code>)</li><li>RFC-002 (Memory Bus Interface Contract) — accepted</li><li>RFC-003 (Event Schema Specification) — accepted</li></ul><h3 id="changed-1" tabindex="-1">Changed <a class="header-anchor" href="#changed-1" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><code>src/index.ts</code> — <code>MCPClient</code>, <code>createLLMAgent</code>, <code>createPipeline</code>, and all builtin tools now exported from the package root</li><li><code>ExecutionContext.signal</code> — AbortSignal now threaded through to builtin tool handlers for cancellation support</li></ul><hr><h2 id="_0-2-1-—-2026-04-05" tabindex="-1"><a href="https://github.com/llmhut/agentvm/compare/v0.2.0...v0.2.1" target="_blank" rel="noreferrer">0.2.1</a> — 2026-04-05 <a class="header-anchor" href="#_0-2-1-—-2026-04-05" aria-label="Permalink to &quot;[0.2.1] — 2026-04-05&quot;">​</a></h2><h3 id="added-2" tabindex="-1">Added <a class="header-anchor" href="#added-2" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><code>ToolRouter.getAvailableTools(allowedToolNames)</code> — filter registered tools by an allowlist</li><li><code>Kernel.registerTool()</code> convenience method (wraps <code>kernel.tools.register()</code> and emits <code>tool:registered</code>)</li><li><code>Kernel.createChannel()</code> convenience method (wraps <code>kernel.broker.createChannel()</code> and emits <code>channel:created</code>)</li><li><code>AgentContract</code> interface — typed input/output contracts with <code>maxLatency</code> and <code>maxCost</code> SLA fields (types defined, runtime enforcement in v0.3.0)</li><li><code>MemoryBus.stats</code> — returns <code>{ namespaces, totalEntries }</code></li><li><code>MessageBroker.stats</code> — returns <code>{ channels, totalMessages }</code></li><li><code>Scheduler.stats</code> — returns <code>{ queued, running, completed, failed }</code></li></ul><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><code>Process._terminate()</code> is now idempotent — calling it twice no longer throws</li><li><code>Kernel.terminate()</code> cleans up process memory namespace when <code>agent.memory.persistent</code> is false</li><li><code>ToolRouter</code> rate limiter key now scoped per <code>toolName:agentName</code> to prevent cross-agent bleed</li></ul><hr><h2 id="_0-2-0-—-2026-03-31" tabindex="-1"><a href="https://github.com/llmhut/agentvm/compare/v0.1.0...v0.2.0" target="_blank" rel="noreferrer">0.2.0</a> — 2026-03-31 <a class="header-anchor" href="#_0-2-0-—-2026-03-31" aria-label="Permalink to &quot;[0.2.0] — 2026-03-31&quot;">​</a></h2><h3 id="added-3" tabindex="-1">Added <a class="header-anchor" href="#added-3" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><code>ToolRouter</code> — central tool registry with registration, invocation, and per-tool rate limiting <ul><li><code>register()</code>, <code>unregister()</code>, <code>getTool()</code>, <code>invoke()</code>, <code>getAvailableTools()</code></li><li><code>ToolNotFoundError</code>, <code>ToolExecutionError</code>, <code>ToolRateLimitError</code> error classes</li><li>Per-tool <code>rateLimit</code> (calls/minute), per-agent counter scoping</li></ul></li><li><code>MessageBroker</code> — inter-agent communication with pub/sub and direct channels <ul><li><code>createChannel()</code>, <code>deleteChannel()</code>, <code>publish()</code>, <code>subscribe()</code>, <code>sendDirect()</code></li><li>Channel history with configurable <code>historyLimit</code></li><li>Direct channel auto-creation (<code>__direct__:a:b</code> naming)</li><li>Subscriber errors caught — bad handlers don&#39;t break delivery</li></ul></li><li><code>Scheduler</code> — multi-strategy task execution engine <ul><li><code>sequential</code> — dependency-ordered, fail-fast</li><li><code>parallel</code> — layer-based parallel execution respecting <code>dependsOn</code></li><li><code>race</code> — first-to-finish wins</li><li><code>conditional</code> — stop on falsy result</li><li><code>enqueue()</code> / <code>enqueueAll()</code> with priority sorting</li><li>Retry policies: <code>fixed</code> and <code>exponential</code> backoff with <code>maxAttempts</code></li><li>Circular dependency detection</li></ul></li><li><code>Kernel.execute()</code> — execute a task on a running process via <code>ExecutionContext</code><ul><li><code>ctx.memory</code> — scoped <code>MemoryAccessor</code> for the process</li><li><code>ctx.useTool()</code> — invoke tools with agent permission enforcement</li><li><code>ctx.publish()</code> — publish to broker channels</li><li><code>ctx.emit()</code> — emit custom <code>agent:&lt;event&gt;</code> events</li><li><code>ctx.signal</code> — AbortSignal for cancellation</li><li>Agent tool allowlist enforcement: undeclared tools are blocked</li><li>Execution metadata stored on process (<code>lastExecution</code>)</li><li>Process transitions to <code>crashed</code> on unhandled handler errors</li></ul></li><li>CLI commands: <code>agentvm init</code>, <code>agentvm start</code>, <code>agentvm spawn</code>, <code>agentvm ps</code>, <code>agentvm kill</code>, <code>agentvm logs</code></li><li><code>MemoryBus.getSharedAccessor()</code> — cross-process shared memory namespace</li><li><code>MemoryEntry</code> TTL support — expired entries auto-deleted on <code>get()</code></li><li><code>Process.signal</code> — <code>AbortSignal</code> automatically aborted on terminate/crash</li><li><code>Process.getMetadata()</code> / <code>setMetadata()</code> — per-process key-value metadata store</li><li><code>Process.info</code> — immutable <code>ProcessInfo</code> snapshot (deep-copied metadata)</li><li><code>Kernel.getProcesses()</code> filter — by <code>agentName</code>, <code>state</code>, or <code>active</code> (running + paused)</li><li><code>Kernel.shutdown()</code> — terminates all active processes</li><li><code>Kernel.onAny()</code> — subscribe to all events with a wildcard handler</li><li><code>Kernel.debug</code> mode — logs all emitted events to <code>console.warn</code></li></ul><hr><h2 id="_0-1-0-—-2026-03-26" tabindex="-1"><a href="https://github.com/llmhut/agentvm/releases/tag/v0.1.0" target="_blank" rel="noreferrer">0.1.0</a> — 2026-03-26 <a class="header-anchor" href="#_0-1-0-—-2026-03-26" aria-label="Permalink to &quot;[0.1.0] — 2026-03-26&quot;">​</a></h2><h3 id="added-4" tabindex="-1">Added <a class="header-anchor" href="#added-4" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Initial project scaffolding — TypeScript, tsup, vitest, ESLint, Prettier, husky</li><li><code>Kernel</code> class — agent registry, process lifecycle, event system</li><li><code>Agent</code> class — typed agent definitions with name validation</li><li><code>Process</code> class — state machine (<code>created → starting → running → paused → terminated | crashed</code>)</li><li><code>MemoryBus</code> — namespaced in-memory key-value store with shared memory namespace</li><li><code>ProcessState</code> enum and all core types in <code>src/core/types.ts</code></li><li><code>KernelEvent</code> structured event system with <code>on()</code> / <code>onAny()</code> / unsubscribe support</li><li><code>Kernel.spawn()</code> — create a running process from a registered agent definition</li><li><code>Kernel.pause()</code>, <code>resume()</code>, <code>terminate()</code> — full process lifecycle management</li><li><code>Kernel.maxProcesses</code> config — cap concurrent active processes</li><li>Unit tests for <code>Agent</code>, <code>Process</code>, <code>Kernel</code>, <code>MemoryBus</code></li><li>GitHub Actions CI/CD (test on push/PR, publish on tag)</li><li>RFC-001 (Process State Machine Design) — accepted</li><li>Architecture Overview documentation</li><li>Getting Started guide</li><li>3 example projects: <code>hello-world.ts</code>, <code>multi-agent.ts</code>, <code>memory-demo.ts</code></li><li>MIT License, Code of Conduct, Contributing guide</li></ul>',33)])])}const g=o(l,[["render",i]]);export{m as __pageData,g as default};
